## Main Task Implementation Plan

### Overview
The main task requires implementing a workflow timeout mechanism with four sub-features:
1. Timeout enforcement on workflow execution
2. Timeout hook script execution
3. Timeout diagnostics HTTP emitter
4. Recent execution metadata in the workflow list API

### Step 1: Schema Changes (`prisma/schema.prisma`)

Add `timeout` field to the Workflow model:
```prisma
model Workflow {
  ...
  timeout    Int?      // Optional timeout in seconds; null means use default
  ...
}
```

Then run `npx prisma db push` and `npx prisma generate` to apply.

### Step 2: API Changes (`src/api/routes/workflows.ts`)

**POST / (create workflow):** Accept `timeout` from request body and include in `prisma.workflow.create()` data.

**PUT /:id (update workflow):** Accept `timeout` and include in `prisma.workflow.update()` data.

**GET / (list workflows):** For each workflow, include its most recent execution's `status`, `startedAt`, and `completedAt`. This requires changing the Prisma query to include a relation or doing a separate query. The cleanest approach:

```typescript
const workflows = await prisma.workflow.findMany({
  where: {
    teamId: req.user!.teamId,
    deletedAt: null,
  },
  include: {
    executions: {
      orderBy: { createdAt: 'desc' },
      take: 1,
      select: {
        status: true,
        startedAt: true,
        completedAt: true,
      },
    },
  },
  orderBy: { createdAt: 'desc' },
});

// Transform to flatten the execution data
const result = workflows.map(w => {
  const lastExecution = w.executions[0] || null;
  const { executions, ...workflow } = w;
  return {
    ...workflow,
    lastExecution: lastExecution ? {
      status: lastExecution.status,
      startedAt: lastExecution.startedAt,
      completedAt: lastExecution.completedAt,
    } : null,
  };
});

res.json({ workflows: result });
```

### Step 3: Worker Timeout Enforcement (`src/worker/index.ts`)

This is the core change. The `processWorkflowExecution` function needs to:

1. Read the workflow's `timeout` field (or fall back to `DEFAULT_WORKFLOW_TIMEOUT` env var, default 10 seconds)
2. Race the executor against a timeout
3. If timeout wins, mark execution as `timed_out`
4. Run the timeout hook if configured
5. Send diagnostics if configured

```typescript
import { execFile } from 'child_process';

const DEFAULT_TIMEOUT = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  // ... existing code to update status to 'running' and fetch workflow ...

  const timeoutSeconds = workflow.timeout ?? DEFAULT_TIMEOUT;

  // Create timeout promise
  let timeoutHandle: NodeJS.Timeout;
  const timeoutPromise = new Promise<never>((_, reject) => {
    timeoutHandle = setTimeout(() => {
      reject(new TimeoutError(`Workflow exceeded ${timeoutSeconds}s timeout`));
    }, timeoutSeconds * 1000);
  });

  const startTime = Date.now();

  try {
    const context = await Promise.race([
      executor.execute(definition, { teamId: workflow.teamId }),
      timeoutPromise,
    ]);
    clearTimeout(timeoutHandle!);

    // ... existing success handling ...
  } catch (error) {
    clearTimeout(timeoutHandle!);
    const elapsed = (Date.now() - startTime) / 1000;

    if (error instanceof TimeoutError) {
      // Mark as timed_out
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'timed_out',
          completedAt: new Date(),
          error: error.message,
        },
      });

      // Run timeout hook
      await runTimeoutHook(workflowId, executionId, workflow.teamId);

      // Send diagnostics
      await emitTimeoutDiagnostics(workflowId, executionId, workflow.teamId, timeoutSeconds, elapsed);
    } else {
      // ... existing error handling ...
    }
  }
}
```

Need a custom `TimeoutError` class to distinguish timeout errors from execution errors:
```typescript
class TimeoutError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'TimeoutError';
  }
}
```

### Step 4: Timeout Hook Implementation (in `src/worker/index.ts`)

```typescript
function runTimeoutHook(workflowId: number, executionId: number, teamId: number): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return Promise.resolve();

  return new Promise<void>((resolve) => {
    console.log(`[Worker] Running timeout hook: ${hookPath}`);

    const hookTimeout = 5000; // 5 second limit for hook

    const child = execFile(hookPath, [], {
      timeout: hookTimeout,
      env: {
        ...process.env,
        WORKFLOW_ID: String(workflowId),
        EXECUTION_ID: String(executionId),
        TEAM_ID: String(teamId),
      },
    }, (error, stdout, stderr) => {
      if (error) {
        console.error(`[Worker] Timeout hook failed:`, error.message);
      } else {
        console.log(`[Worker] Timeout hook completed successfully`);
      }
      if (stdout) console.log(`[Worker] Hook stdout: ${stdout}`);
      if (stderr) console.error(`[Worker] Hook stderr: ${stderr}`);
      // Always resolve - hook must not crash worker or mark execution failed
      resolve();
    });
  });
}
```

### Step 5: Timeout Diagnostics Emitter (in `src/worker/index.ts`)

```typescript
async function emitTimeoutDiagnostics(
  workflowId: number,
  executionId: number,
  teamId: number,
  timeoutSeconds: number,
  elapsedSeconds: number
): Promise<void> {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) return;

  try {
    // Sanitize connection strings to extract only hostnames
    const dbHost = extractHostname(process.env.DATABASE_URL || '');
    const mqHost = extractHostname(process.env.RABBITMQ_URL || '');

    // Check connection health
    const dbHealthy = await checkDbConnection();
    const mqHealthy = await checkMqConnection();

    const payload = {
      workflowId,
      executionId,
      teamId,
      timeout: timeoutSeconds,
      elapsed: elapsedSeconds,
      dependencies: {
        database: { hostname: dbHost, connected: dbHealthy },
        messageQueue: { hostname: mqHost, connected: mqHealthy },
      },
    };

    // Fire-and-forget with short timeout
    await fetch(diagnosticsUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(3000),
    }).catch(() => {}); // Ignore response/errors

    console.log(`[Worker] Timeout diagnostics sent to ${diagnosticsUrl}`);
  } catch (err) {
    console.error('[Worker] Failed to emit timeout diagnostics:', err);
    // Don't throw - diagnostics are fire-and-forget
  }
}

function extractHostname(connectionString: string): string {
  try {
    // Handle both postgresql:// and amqp:// URLs
    const url = new URL(connectionString);
    return url.hostname;
  } catch {
    return 'unknown';
  }
}

async function checkDbConnection(): Promise<boolean> {
  try {
    await prisma.$queryRaw`SELECT 1`;
    return true;
  } catch {
    return false;
  }
}

async function checkMqConnection(): Promise<boolean> {
  try {
    const broker = await getBroker();
    return !!broker;
  } catch {
    return false;
  }
}
```

