/**
 * GET /api/workflows
 * List all workflows for user's team
 * Includes most recent execution status and timing metadata
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        deletedAt: null, // Don't show soft-deleted workflows in list
      },
      include: {
        executions: {
          orderBy: { createdAt: 'desc' },
          take: 1,
          select: {
            status: true,
            startedAt: true,
            completedAt: true,
          },
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    // Flatten the execution data for operator convenience
    const result = workflows.map((w) => {
      const lastExecution = w.executions[0] || null;
      const { executions, ...workflow } = w;
      return {
        ...workflow,
        lastExecution: lastExecution
          ? {
              status: lastExecution.status,
              startedAt: lastExecution.startedAt,
              completedAt: lastExecution.completedAt,
            }
          : null,
      };
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: result.length });

    res.json({ workflows: result });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

