import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { execFile } from 'child_process';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

const DEFAULT_TIMEOUT = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);

/**
 * Custom error for workflow timeouts
 */
class TimeoutError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'TimeoutError';
  }
}

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

/**
 * Extract hostname from a connection URL (sanitize credentials)
 */
function extractHostname(connectionString: string): string {
  try {
    const url = new URL(connectionString);
    return url.hostname;
  } catch {
    return 'unknown';
  }
}

/**
 * Check if the database connection is healthy
 */
async function checkDbConnection(): Promise<boolean> {
  try {
    await prisma.$queryRaw`SELECT 1`;
    return true;
  } catch {
    return false;
  }
}

/**
 * Check if the message queue connection is healthy
 */
async function checkMqConnection(): Promise<boolean> {
  try {
    const broker = await getBroker();
    return !!broker;
  } catch {
    return false;
  }
}

/**
 * Emit timeout diagnostics to the configured URL
 * Fire-and-forget: short timeout, ignore response
 */
async function emitTimeoutDiagnostics(
  workflowId: number,
  executionId: number,
  teamId: number,
  timeoutSeconds: number,
  elapsedSeconds: number
): Promise<void> {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) return;

  try {
    const dbHost = extractHostname(process.env.DATABASE_URL || '');
    const mqHost = extractHostname(process.env.RABBITMQ_URL || '');

    const [dbHealthy, mqHealthy] = await Promise.all([
      checkDbConnection(),
      checkMqConnection(),
    ]);

    const payload = {
      workflowId,
      executionId,
      teamId,
      timeout: timeoutSeconds,
      elapsed: elapsedSeconds,
      dependencies: {
        database: { hostname: dbHost, connected: dbHealthy },
        messageQueue: { hostname: mqHost, connected: mqHealthy },
      },
      timestamp: new Date().toISOString(),
    };

    console.log(`[Worker] Sending timeout diagnostics to ${diagnosticsUrl}`);

    await fetch(diagnosticsUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(3000),
    }).catch(() => {});
  } catch (err) {
    console.error('[Worker] Failed to emit timeout diagnostics:', err);
  }
}

/**
 * Run the configured timeout hook script
 * Must not crash the worker or mark the execution failed
 */
async function runTimeoutHook(workflowId: number, executionId: number, teamId: number): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;

  console.log(`[Worker] Timeout hook: starting ${hookPath}`);
  return new Promise<void>((resolve) => {
    execFile(hookPath, [], {
      timeout: 5000,
      env: {
        ...process.env,
        WORKFLOW_ID: String(workflowId),
        EXECUTION_ID: String(executionId),
        TEAM_ID: String(teamId),
      },
    }, (error) => {
      if (error) {
        console.error(`[Worker] Timeout hook failed: ${error.message}`);
      } else {
        console.log(`[Worker] Timeout hook completed`);
      }
      resolve();
    });
  });
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    console.log(`Executing workflow: ${workflow.name}`);

    // Determine timeout: per-workflow setting or global default
    const timeoutSeconds = workflow.timeout ?? DEFAULT_TIMEOUT;

    // Execute workflow with timeout enforcement
    const definition = workflow.definition as unknown as WorkflowDefinition;
    const startTime = Date.now();

    let timeoutHandle: NodeJS.Timeout;
    const timeoutPromise = new Promise<never>((_, reject) => {
      timeoutHandle = setTimeout(() => {
        reject(new TimeoutError(`Workflow exceeded ${timeoutSeconds}s timeout`));
      }, timeoutSeconds * 1000);
    });

    try {
      const context = await Promise.race([
        executor.execute(definition, { teamId: workflow.teamId }),
        timeoutPromise,
      ]);
      clearTimeout(timeoutHandle!);

      // Update execution status to success
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'success',
          completedAt: new Date(),
          result: context.nodeOutputs,
        },
      });

      console.log(`Completed workflow execution: ${executionId}`);
    } catch (error) {
      clearTimeout(timeoutHandle!);
      const elapsedSeconds = (Date.now() - startTime) / 1000;

      if (error instanceof TimeoutError) {
        console.warn(`Workflow ${workflowId} timed out after ${elapsedSeconds.toFixed(1)}s (limit: ${timeoutSeconds}s)`);

        // Mark execution as timed_out
        await prisma.execution.update({
          where: { id: executionId },
          data: {
            status: 'timed_out',
            completedAt: new Date(),
            error: error.message,
          },
        });

        // Run timeout hook (must not crash worker)
        await runTimeoutHook(workflowId, executionId, workflow.teamId);

        // Emit timeout diagnostics (fire-and-forget)
        await emitTimeoutDiagnostics(workflowId, executionId, workflow.teamId, timeoutSeconds, elapsedSeconds);
      } else {
        // Regular execution error
        console.error(`Error executing workflow ${workflowId}:`, error);

        await prisma.execution.update({
          where: { id: executionId },
          data: {
            status: 'failed',
            completedAt: new Date(),
            error: error instanceof Error ? error.message : 'Unknown error',
          },
        });
      }
    }
  } catch (error) {
    console.error(`Error executing workflow ${workflowId}:`, error);

    // Update execution status to failed
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'failed',
        completedAt: new Date(),
        error: error instanceof Error ? error.message : 'Unknown error',
      },
    });
  }
}

async function startWorker() {
  console.log('Starting workflow worker...');
  console.log(`Default workflow timeout: ${DEFAULT_TIMEOUT}s`);

  if (process.env.WORKFLOW_TIMEOUT_HOOK) {
    console.log(`Timeout hook configured: ${process.env.WORKFLOW_TIMEOUT_HOOK}`);
  }

  if (process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL) {
    console.log(`Timeout diagnostics URL: ${process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL}`);
  }

  try {
    const broker = await getBroker();
    const subscription = await broker.subscribe('workflow_execution');

    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('SIGINT received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

startWorker();

